    code: `'use client'

import { useState, useEffect, useCallback } from 'react'
import { searchCustomers } from '@/actions/customers'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import {
  Popover,
  PopoverContent,
  PopoverTrigger,
} from '@/components/ui/popover'
import { cn } from '@/lib/utils'
import { Check, ChevronsUpDown, Search, Loader2, User } from 'lucide-react'

interface Customer {
  id: number
  name: string
  email: string | null
}

interface Props {
  value?: number
  onSelect: (customer: Customer | null) => void
  disabled?: boolean
  placeholder?: string
  className?: string
}

export function CustomerSelect({ value, onSelect, disabled, placeholder = 'Select customer...', className }: Props) {
  const [open, setOpen] = useState(false)
  const [search, setSearch] = useState('')
  const [loading, setLoading] = useState(false)
  const [customers, setCustomers] = useState<Customer[]>([])
  const [selected, setSelected] = useState<Customer | null>(null)

  // Load initial customer if value is provided
  useEffect(() => {
    if (value && !selected) {
      searchCustomers('').then((results) => {
        const found = results.find(c => c.id === value)
        if (found) setSelected(found)
      })
    }
  }, [value, selected])

  // Search customers
  const doSearch = useCallback(async (query: string) => {
    if (query.length < 2) {
      setCustomers([])
      return
    }
    setLoading(true)
    try {
      const results = await searchCustomers(query)
      setCustomers(results)
    } catch (error) {
      console.error('Failed to search customers:', error)
    } finally {
      setLoading(false)
    }
  }, [])

  // Debounced search
  useEffect(() => {
    const timeout = setTimeout(() => doSearch(search), 300)
    return () => clearTimeout(timeout)
  }, [search, doSearch])

  const handleSelect = (customer: Customer) => {
    setSelected(customer)
    onSelect(customer)
    setOpen(false)
    setSearch('')
  }

  const handleClear = () => {
    setSelected(null)
    onSelect(null)
  }

  return (
    <Popover open={open} onOpenChange={setOpen}>
      <PopoverTrigger asChild>
        <Button
          variant="outline"
          role="combobox"
          aria-expanded={open}
          className={cn('w-full justify-between', className)}
          disabled={disabled}
        >
          {selected ? (
            <div className="flex items-center gap-2 truncate">
              <User className="h-4 w-4 text-gray-400" />
              <span className="truncate">{selected.name}</span>
            </div>
          ) : (
            <span className="text-gray-500">{placeholder}</span>
          )}
          <ChevronsUpDown className="ml-2 h-4 w-4 shrink-0 opacity-50" />
        </Button>

// ... (truncated) ...

            <Button
              variant="ghost"
              size="sm"
              onClick={handleClear}
              className="w-full text-red-600 hover:text-red-700 hover:bg-red-50"
            >
              Clear Selection
            </Button>
          </div>
        )}
      </PopoverContent>
    </Popover>
  )
}
`,
