function validateName(name: string): { valid: boolean; reason?: string } {
  const trimmedName = name.trim()
  if (trimmedName.length < 2) {
    return { valid: false, reason: "Name must be at least 2 characters" }
  }
  if (trimmedName.length > 100) {
    return { valid: false, reason: "Name must be less than 100 characters" }
  }
  if (trimmedName.includes("@")) {
    return { valid: false, reason: "Please enter your name, not email address" }
  }
  const nameRegex = /^[A-Za-z\\s\\-']+$/
  if (!nameRegex.test(trimmedName)) {
    return { valid: false, reason: "Name can only contain letters, spaces, hyphens, and apostrophes" }
  }
  return { valid: true }
}

function validateEmail(email: string): { valid: boolean; reason?: string } {
  const emailRegex = /^[^\\s@]+@[^\\s@]+\\.[^\\s@]+$/
  if (!emailRegex.test(email)) {
    return { valid: false, reason: "Please enter a valid email address" }
  }
  return { valid: true }
}

function validateAustralianPhone(phone: string): { valid: boolean; reason?: string } {
  const cleaned = phone.replace(/\\D/g, "")
  // Australian mobile: 04XX XXX XXX or +614XX XXX XXX
  if (cleaned.startsWith("61") && cleaned.length === 11 && cleaned[2] === "4") {
    return { valid: true }
  }
  if (cleaned.startsWith("04") && cleaned.length === 10) {
    return { valid: true }
  }
  // Landlines: 02, 03, 07, 08
  if (cleaned.startsWith("61") && cleaned.length === 11 && ["2", "3", "7", "8"].includes(cleaned[2])) {
    return { valid: true }
  }
  if (cleaned.length === 10 && ["02", "03", "07", "08"].some((p) => cleaned.startsWith(p))) {
    return { valid: true }
  }
  return { valid: false, reason: "Please enter a valid Australian phone number (e.g., 0412 345 678)" }
}

function normalizeAustralianPhone(phone: string): string {
  const cleaned = phone.replace(/\\D/g, "")
  if (cleaned.startsWith("614") && cleaned.length === 11) {
    return "0" + cleaned.slice(2)
  }
  if (cleaned.startsWith("61") && cleaned.length === 11) {
    return "0" + cleaned.slice(2)
  }
  return cleaned
}

function validateMessage(message: string): { valid: boolean; reason?: string } {
  const trimmedMessage = message.trim()
  if (trimmedMessage.length < 10) {
    return { valid: false, reason: "Message must be at least 10 characters" }
  }
  if (trimmedMessage.length > 5000) {
    return { valid: false, reason: "Message must be less than 5000 characters" }
  }
  return { valid: true }
}

