    code: `'use client'

import { useState, useEffect } from 'react'
import { getCustomerSites } from '@/actions/customers'
import { Button } from '@/components/ui/button'
import {
  Popover,
  PopoverContent,
  PopoverTrigger,
} from '@/components/ui/popover'
import { cn } from '@/lib/utils'
import { Check, ChevronsUpDown, MapPin, Loader2 } from 'lucide-react'
import { Badge } from '@/components/ui/badge'

interface Site {
  id: number
  site_id: string
  site_name: string | null
  address: string
  suburb: string
  is_primary: boolean
}

interface Props {
  customerId: number | null
  value?: number
  onSelect: (site: Site | null) => void
  disabled?: boolean
  placeholder?: string
  className?: string
}

export function SiteSelect({ customerId, value, onSelect, disabled, placeholder = 'Select site...', className }: Props) {
  const [open, setOpen] = useState(false)
  const [loading, setLoading] = useState(false)
  const [sites, setSites] = useState<Site[]>([])
  const [selected, setSelected] = useState<Site | null>(null)

  // Load sites when customer changes
  useEffect(() => {
    if (!customerId) {
      setSites([])
      setSelected(null)
      return
    }

    setLoading(true)
    getCustomerSites(customerId)
      .then((data) => {
        setSites(data)
        // Auto-select primary site if only one site or if value matches
        if (value) {
          const found = data.find(s => s.id === value)
          if (found) setSelected(found)
        } else if (data.length === 1) {
          setSelected(data[0])
          onSelect(data[0])
        } else {
          const primary = data.find(s => s.is_primary)
          if (primary) {
            setSelected(primary)
            onSelect(primary)
          }
        }
      })
      .catch((error) => {
        console.error('Failed to load sites:', error)
      })
      .finally(() => {
        setLoading(false)
      })
  }, [customerId, value, onSelect])

  const handleSelect = (site: Site) => {
    setSelected(site)
    onSelect(site)
    setOpen(false)
  }

  const handleClear = () => {
    setSelected(null)
    onSelect(null)
  }

  const isDisabled = disabled || !customerId

  return (
    <Popover open={open} onOpenChange={setOpen}>
      <PopoverTrigger asChild>
        <Button
          variant="outline"
          role="combobox"
          aria-expanded={open}
          className={cn('w-full justify-between', className)}
          disabled={isDisabled}
        >
          {loading ? (
            <div className="flex items-center gap-2">
              <Loader2 className="h-4 w-4 animate-spin" />
              Loading sites...

// ... (truncated) ...

            <Button
              variant="ghost"
              size="sm"
              onClick={handleClear}
              className="w-full text-red-600 hover:text-red-700 hover:bg-red-50"
            >
              Clear Selection
            </Button>
          </div>
        )}
      </PopoverContent>
    </Popover>
  )
}
`,
