// Listens for FCM foreground messages and shows in-app notifications
function ForegroundMessageListener() {
  const { addNotification } = useNotifications()

  useEffect(() => {
    let unsubscribe: (() => void) | undefined

    import('@/lib/push-notifications').then(({ onForegroundMessage }) => {
      unsubscribe = onForegroundMessage((payload) => {
        // Map push type to in-app notification type
        const typeMap: Record<string, 'payment' | 'booking' | 'info' | 'warning' | 'email' | 'sms'> = {
          payment: 'payment',
          booking: 'booking',
          overdue: 'warning',
          lead: 'info',
          email: 'email',
          sms: 'sms',
          system: 'info',
        }
        const notifType = (payload.type && typeMap[payload.type]) || 'info'

        // Build rich message with details
        let message = payload.body
        if (payload.customerName && !message.includes(payload.customerName)) {
          message = payload.customerName + ' \\u2014 ' + message
        }
        if (payload.amount && !message.includes('$')) {
          message += ' ($' + payload.amount + ')'
        }

        // Build action label based on type
        const actionLabel = payload.type === 'payment' || payload.type === 'overdue'
          ? 'View Invoice'
          : payload.type === 'booking'
          ? 'View Booking'
          : payload.type === 'sms'
          ? 'View SMS'
          : 'View'

        addNotification({
          type: notifType,
          title: payload.title,
          message,
          ...(payload.url && {
            action: {
              label: actionLabel,
              onClick: () => window.location.href = payload.url!,
            },
          }),
        })
      })
    }).catch(() => {})

    return () => unsubscribe?.()
  }, [addNotification])

  return null
}

