    code: `'use client'

import { useState, useEffect, useRef, useCallback, useMemo } from 'react'
import {
  Search, Save, Rocket, Upload, GitBranch, Download,
  Eye, SidebarOpen, X as XIcon, Terminal, FileText,
  FolderTree, MessageSquare, Keyboard, Maximize2,
  type LucideIcon,
} from 'lucide-react'
import { cn } from '@/lib/utils'

interface Command {
  id: string
  label: string
  description?: string
  shortcut?: string
  icon: LucideIcon
  category: 'actions' | 'navigation' | 'view'
  action: () => void
}

interface CommandPaletteProps {
  open: boolean
  onClose: () => void
  commands: Command[]
}

export function CommandPalette({ open, onClose, commands }: CommandPaletteProps) {
  const [query, setQuery] = useState('')
  const inputRef = useRef<HTMLInputElement>(null)
  const [selectedIndex, setSelectedIndex] = useState(0)

  const filtered = useMemo(() => {
    if (!query.trim()) return commands
    const q = query.toLowerCase()
    return commands.filter(c =>
      c.label.toLowerCase().includes(q) ||
      c.description?.toLowerCase().includes(q) ||
      c.category.toLowerCase().includes(q)
    )
  }, [commands, query])

  // Group by category
  const grouped = useMemo(() => {
    const groups: Record<string, Command[]> = {}
    for (const cmd of filtered) {
      if (!groups[cmd.category]) groups[cmd.category] = []
      groups[cmd.category].push(cmd)
    }
    return groups
  }, [filtered])

  const flatFiltered = useMemo(() => filtered, [filtered])

  // Reset on open
  useEffect(() => {
    if (open) {
      setQuery('')
      setSelectedIndex(0)
      requestAnimationFrame(() => inputRef.current?.focus())
    }
  }, [open])

  // Keyboard navigation
  const handleKeyDown = useCallback((e: React.KeyboardEvent) => {
    if (e.key === 'Escape') {
      onClose()
    } else if (e.key === 'ArrowDown') {
      e.preventDefault()
      setSelectedIndex(i => Math.min(i + 1, flatFiltered.length - 1))
    } else if (e.key === 'ArrowUp') {
      e.preventDefault()
      setSelectedIndex(i => Math.max(i - 1, 0))
    } else if (e.key === 'Enter') {
      e.preventDefault()
      if (flatFiltered[selectedIndex]) {
        flatFiltered[selectedIndex].action()
        onClose()
      }
    }
  }, [flatFiltered, selectedIndex, onClose])

  // Reset selection when filter changes
  useEffect(() => {
    setSelectedIndex(0)
  }, [query])

  if (!open) return null

  const categoryLabels: Record<string, string> = {
    actions: 'Actions',
    navigation: 'Navigation',
    view: 'View',
  }

  let flatIndex = 0

  return (
    <div className="fixed inset-0 z-[100] flex items-start justify-center pt-[10vh] sm:pt-[20vh]" onClick={onClose}>
      {/* Backdrop */}

// ... (truncated) ...

        <div className="px-4 py-2 border-t border-forge-border bg-forge-surface/50 flex items-center justify-between">
          <div className="flex items-center gap-3 text-[10px] text-forge-text-dim">
            <span className="flex items-center gap-1"><kbd className="px-1 py-0.5 bg-white border border-forge-border rounded text-[9px]">&uarr;&darr;</kbd> navigate</span>
            <span className="flex items-center gap-1"><kbd className="px-1 py-0.5 bg-white border border-forge-border rounded text-[9px]">&crarr;</kbd> select</span>
          </div>
          <div className="flex items-center gap-1 text-[10px] text-forge-text-dim">
            <Keyboard className="w-3 h-3" />
            <span>{flatFiltered.length} commands</span>
          </div>
        </div>
      </div>
    </div>
  )
}
`,
