    code: `"use client"

import { useState, useEffect, useCallback } from "react"
import { setOnUpdateFound, skipWaiting } from "@/lib/sw-register"
import { X, RefreshCw } from "lucide-react"

export function SWUpdateToast() {
  const [showUpdate, setShowUpdate] = useState(false)

  useEffect(() => {
    setOnUpdateFound(() => {
      setShowUpdate(true)
    })
  }, [])

  // Auto-dismiss after 30 seconds
  useEffect(() => {
    if (!showUpdate) return
    const timer = setTimeout(() => setShowUpdate(false), 30000)
    return () => clearTimeout(timer)
  }, [showUpdate])

  const handleRefresh = useCallback(() => {
    skipWaiting()
    // controllerchange listener in sw-register will reload
  }, [])

  if (!showUpdate) return null

  return (
    <div className="fixed bottom-20 md:bottom-5 left-1/2 -translate-x-1/2 z-50 animate-slide-up">
      <div className="flex items-center gap-3 bg-green-600 text-white px-4 py-3 rounded-xl shadow-lg">
        <RefreshCw className="h-4 w-4 shrink-0" />
        <span className="text-sm font-medium">Update available</span>
        <button
          onClick={handleRefresh}
          className="bg-white text-green-700 text-sm font-semibold px-3 py-1 rounded-lg hover:bg-green-50 transition-colors"
        >
          Refresh
        </button>
        <button
          onClick={() => setShowUpdate(false)}
          className="text-white/80 hover:text-white transition-colors"
          aria-label="Dismiss"
        >
          <X className="h-4 w-4" />
        </button>
      </div>
    </div>
  )
}
`,
