import { useEffect, useState, useCallback } from "react"
import { useRouter } from "next/navigation"
import { getPortalUserEmail } from "@/lib/portal-auth"
import { getCachedBookings, setCachedBookings, isBookingsCacheFresh } from "@/lib/portal-cache"
import { Button } from "@/components/ui/button"
import { CalendarDays, MapPin, Package, CheckCircle2, Clock, AlertCircle, Plus, RotateCcw, List, Trash2, ArrowLeft, RefreshCw } from "lucide-react"
import { Skeleton } from "@/components/ui/skeleton"
