    code: `'use client'

import { forwardRef, type InputHTMLAttributes, useRef, useImperativeHandle, useState } from 'react'
import { motion, AnimatePresence } from 'framer-motion'
import { Search, X } from 'lucide-react'
import { cn } from '@/lib/utils'

export interface SquareSearchProps extends Omit<InputHTMLAttributes<HTMLInputElement>, 'size'> {
  onClear?: () => void
  showClearButton?: boolean
}

/**
 * SquareSearch - Android SearchBar.kt exact match
 *
 * Specs:
 * - Height: 48px
 * - Border radius: 12px
 * - Background: #F3F3F3 (gray150)
 * - Search icon: 20px, color #757575, left side
 * - Placeholder: color #757575, 16px
 * - Input text: #111111, 16px
 * - Clear button: X icon, visible when text present, right side
 * - Focus state: border 1px #111111
 * - Padding: 12px horizontal
 * - Animation: Subtle scale on focus, clear button fade in/out
 */
export const SquareSearch = forwardRef<HTMLInputElement, SquareSearchProps>(
  (
    {
      className,
      value,
      onChange,
      onClear,
      showClearButton = true,
      placeholder = 'Search',
      ...props
    },
    ref
  ) => {
    const inputRef = useRef<HTMLInputElement>(null)
    const [isFocused, setIsFocused] = useState(false)
    useImperativeHandle(ref, () => inputRef.current!)

    const hasValue = value !== undefined && value !== ''

    const handleClear = () => {
      if (onClear) {
        onClear()
      }
      inputRef.current?.focus()
    }

    return (
      <motion.div
        animate={{
          scale: isFocused ? 1.01 : 1
        }}
        transition={{ duration: 0.15, ease: 'easeOut' }}
        className={cn(
          // Base styles - Android SearchBar.kt exact specs
          'h-[48px] flex items-center gap-3 px-3',
          'rounded-[12px]',
          'bg-[#F3F3F3]',
          // Focus state: 1px border #111111
          'border border-transparent',
          'transition-[border-color] duration-150',
          isFocused && 'border-[#111111]',
          className
        )}
      >
        {/* Search icon - 20px, #757575, left side */}
        <Search
          className="h-5 w-5 shrink-0"
          style={{ color: '#757575' }}
          strokeWidth={2}
        />

        {/* Input - text #111111, placeholder #757575, 16px */}
        <input
          ref={inputRef}
          type="text"
          value={value}
          onChange={onChange}
          placeholder={placeholder}
          onFocus={() => setIsFocused(true)}
          onBlur={() => setIsFocused(false)}
          className={cn(
            'flex-1 bg-transparent border-none outline-none',
            'text-[16px] leading-normal',
            'text-[#111111]',
            'placeholder:text-[#757575]'
          )}
          style={{ fontSize: '16px' }}
          {...props}
        />

        {/* Clear button - X icon, right side, fade in/out */}
        <AnimatePresence>
          {showClearButton && hasValue && (

// ... (truncated) ...

            transition={{ duration: 0.2 }}
            className="overflow-hidden"
          >
            <div className={cn('px-4 pb-3', className)}>
              <SquareSearch ref={ref} {...props} />
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    )
  }
)

SquareExpandableSearch.displayName = 'SquareExpandableSearch'
`,
