    code: `"use client"

import { useState, useEffect, useCallback } from "react"
import { Bell, X } from "lucide-react"

const DISMISS_KEY = "awb_portal_push_dismissed"
const DISMISS_DAYS = 30
const SUBSCRIBED_KEY = "awb_portal_push_subscribed"
const MIN_VISITS = 2
const VISIT_KEY = "awb_portal_visit_count"

export function PortalPushPrompt() {
  const [show, setShow] = useState(false)

  useEffect(() => {
    if (typeof window === "undefined") return
    if (!("Notification" in window)) return
    if (!("serviceWorker" in navigator)) return
    if (Notification.permission === "denied") return

    // Track visits
    const visits = parseInt(localStorage.getItem(VISIT_KEY) || "0", 10) + 1
    localStorage.setItem(VISIT_KEY, String(visits))

    // Already subscribed - silently refresh token
    if (localStorage.getItem(SUBSCRIBED_KEY) === "true") {
      if (Notification.permission === "granted") {
        import("@/lib/portal-push").then(({ subscribeToPortalPush }) => {
          subscribeToPortalPush().catch(() => {})
        }).catch(() => {})
        return
      }
      localStorage.removeItem(SUBSCRIBED_KEY)
    }

    // Permission already granted but not marked - subscribe silently
    if (Notification.permission === "granted") {
      import("@/lib/portal-push").then(({ subscribeToPortalPush }) => {
        subscribeToPortalPush().then((token) => {
          if (token) localStorage.setItem(SUBSCRIBED_KEY, "true")
        }).catch(() => {})
      }).catch(() => {})
      return
    }

    // Don't show until enough visits
    if (visits < MIN_VISITS) return

    // Check dismiss cooldown
    const dismissed = localStorage.getItem(DISMISS_KEY)
    if (dismissed) {
      const daysSince = (Date.now() - parseInt(dismissed, 10)) / (1000 * 60 * 60 * 24)
      if (daysSince < DISMISS_DAYS) return
    }

    const timer = setTimeout(() => setShow(true), 3000)
    return () => clearTimeout(timer)
  }, [])

  const handleEnable = useCallback(async () => {
    try {
      const { subscribeToPortalPush } = await import("@/lib/portal-push")
      const token = await subscribeToPortalPush()
      if (token) {
        localStorage.setItem(SUBSCRIBED_KEY, "true")
      }
    } catch (err) {
      console.error("[PortalPush] Enable failed:", err)
    }
    setShow(false)
  }, [])

  const handleDismiss = useCallback(() => {
    localStorage.setItem(DISMISS_KEY, String(Date.now()))
    setShow(false)
  }, [])

  if (!show) return null

  return (
    <div className="fixed bottom-20 md:bottom-5 left-4 right-4 md:left-1/2 md:-translate-x-1/2 md:max-w-sm z-40">
      <div className="bg-white border border-gray-200 rounded-2xl shadow-lg p-4">
        <div className="flex items-start gap-3">
          <div className="bg-green-50 rounded-xl p-2 shrink-0">
            <Bell className="h-5 w-5 text-green-600" />
          </div>
          <div className="flex-1 min-w-0">
            <p className="text-sm font-semibold text-gray-900">
              Stay Updated
            </p>
            <p className="text-xs text-gray-500 mt-0.5">
              Get notified about invoices, collections, and payments
            </p>
          </div>
          <button
            onClick={handleDismiss}
            className="text-gray-400 hover:text-gray-600 shrink-0"
            aria-label="Dismiss"
          >
            <X className="h-4 w-4" />

// ... (truncated) ...

          >
            Enable
          </button>
          <button
            onClick={handleDismiss}
            className="flex-1 bg-gray-100 text-gray-600 text-sm font-medium py-2.5 rounded-xl hover:bg-gray-200 transition-colors"
          >
            Not now
          </button>
        </div>
      </div>
    </div>
  )
}
`,
